import React, { useState } from 'react';
import './calc.css';
function Calc() {
  const [number, setNumber] = useState(0);

  const Plus = () => {
    setNumber(number + 1);
  }

  const onDecrease = () => {
    setNumber(number - 1);
  }

  return (
    <div className='wrap'>
      <div className='calc'>
        <div className='monitor'>{number}</div>
        <button>0</button>
        <button>1</button>
        <button>2</button>
        <button>3</button>
        <button>4</button>
        <button>5</button>
        <button>6</button>
        <button>7</button>
        <button>8</button>
        <button>9</button>
        <button>🔙</button>
        <button>🟰</button>
        <button>➖</button>
        <button onClick={Plus}>➕</button>
        <button>✖️</button>
        <button>➗</button>
      </div>
    </div>
  );
}

export default Calc;
